1	import {
2	  Entity,
3	  PrimaryGeneratedColumn,
4	  Column,
5	  CreateDateColumn,
6	  UpdateDateColumn,
7	  OneToMany,
8	} from 'typeorm';
9	import { OrderItem } from './order-item.entity';
10	
11	export enum OrderStatus {
12	  PENDING = 'pending',
13	  CONFIRMED = 'confirmed',
14	  FULFILLED = 'fulfilled',
15	  CANCELLED = 'cancelled',
16	}
17	
18	@Entity('orders')
19	export class Order {
20	  @PrimaryGeneratedColumn('uuid')
21	  id: string;
22	
23	  @Column({ type: 'uuid' })
24	  store_id: string;
25	
26	  @Column({ type: 'uuid' })
27	  user_id: string;
28	
29	  @Column({
30	    type: 'enum',
31	    enum: OrderStatus,
32	    default: OrderStatus.PENDING,
33	  })
34	  status: OrderStatus;
35	
36	  @Column({ unique: true })
37	  idempotency_key: string;
38	
39	  @Column({ type: 'int' })
40	  total_cents: number;
41	
42	  @Column({ type: 'int', default: 0 })
43	  discount_cents: number;
44	
45	  @Column({ type: 'uuid', nullable: true })
46	  coupon_id: string;
47	
48	  @Column({ type: 'uuid', nullable: true })
49	  promotion_id: string;
50	
51	  @Column({ type: 'text', nullable: true })
52	  internal_notes: string;
53	
54	  @CreateDateColumn({ type: 'timestamptz' })
55	  created_at: Date;
56	
57	  @UpdateDateColumn({ type: 'timestamptz' })
58	  updated_at: Date;
59	
60	  @OneToMany(() => OrderItem, (item) => item.order)
61	  items: OrderItem[];
62	}
