1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository } from 'typeorm';
4	import { AuditLog } from './entities/audit-log.entity';
5	
6	const SENSITIVE_KEYS = ['password', 'hash', 'secret', 'token', 'encrypted', 'notes', 'key'];
7	
8	function maskSensitiveFields(
9	  detail: Record<string, any> | null,
10	): Record<string, any> | null {
11	  if (!detail || typeof detail !== 'object') return detail;
12	
13	  const masked: Record<string, any> = {};
14	  for (const [key, value] of Object.entries(detail)) {
15	    const lowerKey = key.toLowerCase();
16	    const isSensitive = SENSITIVE_KEYS.some((sk) => lowerKey.includes(sk));
17	    if (isSensitive) {
18	      masked[key] = '[REDACTED]';
19	    } else if (value && typeof value === 'object' && !Array.isArray(value)) {
20	      masked[key] = maskSensitiveFields(value);
21	    } else {
22	      masked[key] = value;
23	    }
24	  }
25	  return masked;
26	}
27	
28	@Injectable()
29	export class AuditService {
30	  constructor(
31	    @InjectRepository(AuditLog)
32	    private readonly auditRepo: Repository<AuditLog>,
33	  ) {}
34	
35	  async log(
36	    actorId: string | null,
37	    action: string,
38	    resourceType?: string,
39	    resourceId?: string,
40	    detail?: Record<string, any>,
41	    traceId?: string,
42	  ): Promise<AuditLog> {
43	    const entry = this.auditRepo.create({
44	      actor_id: actorId,
45	      action,
46	      resource_type: resourceType || null,
47	      resource_id: resourceId || null,
48	      detail: detail || null,
49	      trace_id: traceId || null,
50	    });
51	    return this.auditRepo.save(entry);
52	  }
53	
54	  async findAll(filters: {
55	    actorId?: string;
56	    action?: string;
57	    from?: string;
58	    to?: string;
59	    page?: number;
60	    limit?: number;
61	  }): Promise<{ data: AuditLog[]; total: number; page: number; limit: number }> {
62	    const page = filters.page || 1;
63	    const limit = filters.limit || 25;
64	
65	    const qb = this.auditRepo.createQueryBuilder('log');
66	
67	    if (filters.actorId) {
68	      qb.andWhere('log.actor_id = :actorId', { actorId: filters.actorId });
69	    }
70	    if (filters.action) {
71	      qb.andWhere('log.action = :action', { action: filters.action });
72	    }
73	    if (filters.from) {
74	      qb.andWhere('log.created_at >= :from', { from: filters.from });
75	    }
76	    if (filters.to) {
77	      qb.andWhere('log.created_at <= :to', { to: filters.to });
78	    }
79	
80	    qb.orderBy('log.created_at', 'DESC');
81	    qb.skip((page - 1) * limit);
82	    qb.take(limit);
83	
84	    const [data, total] = await qb.getManyAndCount();
85	    return { data, total, page, limit };
86	  }
87	
88	  async exportCsv(from?: string, to?: string): Promise<string> {
89	    const qb = this.auditRepo.createQueryBuilder('log');
90	
91	    if (from) {
92	      qb.andWhere('log.created_at >= :from', { from });
93	    }
94	    if (to) {
95	      qb.andWhere('log.created_at <= :to', { to });
96	    }
97	
98	    qb.orderBy('log.created_at', 'ASC');
99	    const logs = await qb.getMany();
100	
101	    const headers = [
102	      'id',
103	      'actor_id',
104	      'action',
105	      'resource_type',
106	      'resource_id',
107	      'detail',
108	      'trace_id',
109	      'created_at',
110	    ];
111	
112	    const rows = logs.map((log) => {
113	      const maskedDetail = maskSensitiveFields(log.detail);
114	      return [
115	        log.id,
116	        log.actor_id || '',
117	        escapeCsvField(log.action),
118	        log.resource_type || '',
119	        log.resource_id || '',
120	        escapeCsvField(maskedDetail ? JSON.stringify(maskedDetail) : ''),
121	        log.trace_id || '',
122	        log.created_at.toISOString(),
123	      ].join(',');
124	    });
125	
126	    return [headers.join(','), ...rows].join('\n');
127	  }
128	}
129	
130	function escapeCsvField(value: string): string {
131	  if (
132	    value.includes(',') ||
133	    value.includes('"') ||
134	    value.includes('\n')
135	  ) {
136	    return `"${value.replace(/"/g, '""')}"`;
137	  }
138	  return value;
139	}
