409	          `Coupon ${coupon.id} (store=${coupon.store_id}) rejected for order in store ${storeId} — cross-store coupon application blocked.`,
410	        );
411	      }
412	    }
413	
414	    // 8. Max one coupon + one automatic promotion per order
415	    let totalDiscount = 0;
416	    let selectedPromotion: Promotion | null = null;
417	
418	    if (bestAutoPromo) {
419	      const autoDiscount = this.calculateDiscount(bestAutoPromo, orderTotalCents);
420	      if (autoDiscount > 0) {
421	        totalDiscount += autoDiscount;
422	        selectedPromotion = bestAutoPromo;
423	      }
424	    }
425	
426	    if (couponPromotion) {
427	      const couponDiscount = this.calculateDiscount(couponPromotion, orderTotalCents);
428	      if (couponDiscount > 0) {
429	        totalDiscount += couponDiscount;
430	        // If no auto promo was selected, the coupon promotion becomes the selected one
431	        if (!selectedPromotion) {
432	          selectedPromotion = couponPromotion;
433	        }
434	      }
435	    }
436	
437	    return {
438	      selectedPromotion,
439	      selectedCoupon,
440	      totalDiscount,
441	    };
442	  }
