444	  @Cron(CronExpression.EVERY_HOUR)
445	  async handleExpiredCoupons(): Promise<void> {
446	    const now = new Date();
447	    const result = await this.couponRepo
448	      .createQueryBuilder()
449	      .update(Coupon)
450	      .set({ status: CouponStatus.EXPIRED })
451	      .where('status = :status', { status: CouponStatus.ACTIVE })
452	      .andWhere('ends_at IS NOT NULL')
453	      .andWhere('ends_at < :now', { now })
454	      .execute();
455	
456	    if (result.affected && result.affected > 0) {
457	      this.logger.log(`Expired ${result.affected} coupons`);
458	    }
