9	  canActivate(context: ExecutionContext): boolean {
10	    const requiredRoles = this.reflector.getAllAndOverride<string[]>(ROLES_KEY, [
11	      context.getHandler(),
12	      context.getClass(),
13	    ]);
14	    if (!requiredRoles || requiredRoles.length === 0) {
15	      return true;
16	    }
17	    const { user } = context.switchToHttp().getRequest();
18	    if (!user) return false;
19	    return requiredRoles.includes(user.role);
20	  }
21	}
