107	    dto: GeneratePaperDto,
108	    user: any,
109	    requestedStoreId?: string,
110	  ): Promise<Paper> {
111	    const storeId = this.resolveTargetStoreForGenerate(user, requestedStoreId);
112	    const userId: string = user?.id;
113	    const { generationRule } = dto;
114	    let questions: Question[];
115	
116	    if (generationRule.type === 'random') {
117	      const count = generationRule.count ?? 10;
118	      const qb = this.questionRepo
119	        .createQueryBuilder('q')
120	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
121	
122	      if (storeId) {
123	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
124	          storeId,
125	        });
126	      }
127	
128	      questions = await qb
129	        .orderBy('RANDOM()')
130	        .limit(count)
131	        .getMany();
132	    } else {
133	      // rule-based
134	      const qb = this.questionRepo
135	        .createQueryBuilder('q')
136	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
137	
138	      if (storeId) {
139	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
140	          storeId,
141	        });
142	      }
143	
144	      const filters = generationRule.filters ?? {};
145	      if (filters.type) {
146	        qb.andWhere('q.type = :type', { type: filters.type });
147	      }
148	
149	      const count = generationRule.count;
150	      if (count) {
151	        qb.limit(count);
152	      }
153	
154	      questions = await qb.getMany();
155	    }
156	
157	    const paper = this.paperRepo.create({
158	      name: dto.name,
159	      generation_rule: generationRule as any,
160	      created_by: userId,
161	      store_id: storeId ?? null,
162	    });
163	
164	    const savedPaper = await this.paperRepo.save(paper);
165	
166	    const paperQuestions = questions.map((q, index) =>
167	      this.paperQuestionRepo.create({
168	        paper_id: savedPaper.id,
169	        question_id: q.id,
170	        position: index + 1,
171	      }),
172	    );
173	
174	    await this.paperQuestionRepo.save(paperQuestions);
175	    savedPaper.paper_questions = paperQuestions;
