180	  async startAttempt(paperId: string, userId: string): Promise<Attempt> {
181	    const paper = await this.paperRepo.findOne({ where: { id: paperId } });
182	    if (!paper) {
183	      throw new NotFoundException('Paper not found');
184	    }
185	
186	    const attempt = this.attemptRepo.create({
187	      paper_id: paperId,
188	      user_id: userId,
189	      status: AttemptStatus.IN_PROGRESS,
190	      started_at: new Date(),
191	    });
192	
193	    return this.attemptRepo.save(attempt);
194	  }
195	
196	  async submitAttempt(
197	    attemptId: string,
198	    answers: SubmitAnswerDto[],
199	    userId: string,
200	  ): Promise<Attempt> {
201	    const attempt = await this.attemptRepo.findOne({
202	      where: { id: attemptId },
203	    });
204	
205	    if (!attempt) {
206	      throw new NotFoundException('Attempt not found');
207	    }
208	
209	    if (attempt.user_id !== userId) {
210	      throw new BadRequestException('Attempt does not belong to this user');
211	    }
212	
213	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
214	      throw new BadRequestException('Attempt is not in progress');
215	    }
216	
217	    const now = new Date();
218	    let correctCount = 0;
219	    let totalObjective = 0;
220	    const attemptAnswers: AttemptAnswer[] = [];
221	
222	    for (const ans of answers) {
223	      const question = await this.questionRepo.findOne({
224	        where: { id: ans.questionId },
225	      });
226	
227	      if (!question) {
228	        throw new NotFoundException(`Question ${ans.questionId} not found`);
229	      }
230	
231	      let isCorrect: boolean | null = null;
232	
233	      if (question.type === QuestionType.OBJECTIVE) {
234	        totalObjective++;
235	
236	        if (ans.selectedOptionId) {
237	          const option = await this.optionRepo.findOne({
238	            where: { id: ans.selectedOptionId },
239	          });
240	
241	          if (option) {
242	            isCorrect = option.is_correct;
243	            if (isCorrect) {
244	              correctCount++;
245	            }
246	          } else {
247	            isCorrect = false;
248	          }
249	        } else {
250	          isCorrect = false;
251	        }
252	      }
253	      // subjective: is_correct remains null
254	
255	      const attemptAnswer = this.answerRepo.create({
256	        attempt_id: attemptId,
257	        question_id: ans.questionId,
258	        selected_option_id: ans.selectedOptionId ?? null,
259	        text_answer: ans.textAnswer ?? null,
260	        is_correct: isCorrect,
261	      });
262	
263	      attemptAnswers.push(attemptAnswer);
264	    }
265	
266	    await this.answerRepo.save(attemptAnswers);
267	
268	    const score =
269	      totalObjective > 0
270	        ? Math.round((correctCount / totalObjective) * 10000) / 100
271	        : null;
272	
273	    attempt.status = AttemptStatus.GRADED;
274	    attempt.graded_at = now;
275	    attempt.submitted_at = now;
276	    attempt.score = score;
277	    attempt.answers = attemptAnswers;
278	
279	    return this.attemptRepo.save(attempt);
280	  }
