1	#!/usr/bin/env node
2	/**
3	 * API-test DB preflight.
4	 *
5	 * Runs before `npm run test:api`. Verifies the PostgreSQL database at
6	 * DATABASE_URL (or the default dev URL) is actually reachable and
7	 * responsive to a real protocol handshake — not just TCP.
8	 *
9	 * Rationale: a TCP connection can succeed against a misconfigured
10	 * docker port-forwarder while the real protocol layer times out (we
11	 * hit exactly that during the F-03 remediation pass). When that
12	 * happens, Jest spends minutes retrying and then reports every test
13	 * as "failed to set up" with a giant stack trace, which obscures the
14	 * actual problem. A fast protocol-level preflight turns that into a
15	 * single clear line and exit 1, so operators see what's wrong.
16	 *
17	 * Usage:
18	 *   node scripts/check-test-db.js            # uses DATABASE_URL or default
19	 *   DATABASE_URL=... node scripts/check-test-db.js
20	 */
21	
22	const DEFAULT_URL =
23	  'postgres://proctorworks:proctorworks@127.0.0.1:5433/proctorworks';
24	const url = process.env.DATABASE_URL || DEFAULT_URL;
25	const TIMEOUT_MS = 5000;
26	
27	function fatal(msg) {
28	  console.error(''); // spacer so it stands out in jest output
29	  console.error('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
30	  console.error('API TEST DB PREFLIGHT FAILED');
31	  console.error('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
32	  console.error(msg);
33	  console.error('');
34	  console.error('URL tried : ' + url);
35	  console.error('');
36	  console.error('Fix options:');
37	  console.error('  1. docker compose up -d db   (default: 127.0.0.1:5433)');
38	  console.error('  2. DATABASE_URL=postgres://user:pass@host:port/db \\');
39	  console.error('       npm run test:api');
40	  console.error('  3. On hosts where docker port-forwarding is broken,');
41	  console.error('     start postgres in host-network mode, e.g.:');
42	  console.error('       docker run --rm -d --name pg-test --network host \\');
43	  console.error('         -e POSTGRES_USER=proctorworks \\');
44	  console.error('         -e POSTGRES_PASSWORD=proctorworks \\');
45	  console.error('         -e POSTGRES_DB=proctorworks \\');
46	  console.error('         -e PGPORT=25432 postgres:16');
47	  console.error('     then:');
48	  console.error('       DATABASE_URL=postgres://proctorworks:proctorworks@127.0.0.1:25432/proctorworks \\');
49	  console.error('         npm run test:api');
50	  console.error('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
51	  process.exit(1);
52	}
53	
54	let Client;
55	try {
56	  ({ Client } = require('pg'));
57	} catch (_e) {
58	  fatal(
59	    'The `pg` module is not installed. Run `npm install` first so jest ' +
60	      'and its transitive deps are available, then re-run the preflight.',
61	  );
62	}
63	
64	(async () => {
65	  const client = new Client({ connectionString: url });
66	  let settled = false;
67	
68	  const timer = setTimeout(() => {
69	    if (settled) return;
70	    settled = true;
71	    try {
72	      client.end().catch(() => {});
73	    } catch (_e) {
74	      // client may not be connected yet — ignore
75	    }
76	    fatal(
77	      `Timed out after ${TIMEOUT_MS}ms waiting for a Postgres handshake. ` +
78	        'TCP may be reachable while the protocol layer is not (common ' +
79	        'symptom of a broken docker port-forwarder or stale docker-proxy ' +
80	        'on the host).',
81	    );
82	  }, TIMEOUT_MS);
83	
84	  try {
85	    await client.connect();
86	    const { rows } = await client.query('SELECT 1 AS ok');
87	    if (rows[0].ok !== 1) {
88	      throw new Error('unexpected SELECT 1 result');
89	    }
90	    clearTimeout(timer);
91	    settled = true;
92	    await client.end();
93	    console.log('✓ Test DB reachable at ' + url);
94	    process.exit(0);
95	  } catch (e) {
96	    if (settled) return;
97	    settled = true;
98	    clearTimeout(timer);
99	    fatal(
100	      `Failed to connect to the test database.\n\nError: ${e.message}\n` +
101	        `Code : ${e.code || 'n/a'}`,
102	    );
103	  }
104	})();
